// Get file contents as text
window.getResourceAsTextCache = {};
window.getResourceAsText = function (file) {
    if (window.getResourceAsTextCache[file] == null) {
        const resource = window.getResource(file);
        // Base64 URI
        if (resource.startsWith('data:')) {
            const base64 = resource.split(',')[1];
            window.getResourceAsTextCache[file] = decodeURIComponent(escape(window.atob(base64)));
        }
        // File URL
        else {
            const xhr = new XMLHttpRequest();
            xhr.open('GET', resource, false);
            xhr.send();
            window.getResourceAsTextCache[file] = xhr.responseText ?? null;
        }
    }
    return window.getResourceAsTextCache[file];
}

// Get file contents as base64 URI
window.getResourceAsBase64 = async function (file) {
    const resource = window.getResource(file);
    // Base64 URI
    if (resource.startsWith('data:')) {
        return resource;
    }
    // File URL
    else {
        // Convert stored font file to base64 data URI
        const response = await fetch(resource);
        const blob = await response.blob();
        return await new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result);
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    }
}

// Get audio resource URI
window.getAudioUrl = function (file) {
    // Browser extension ships with audio, userscript and Android use external hosted audio
    // Audio is too heavy to include as base64 URI
    if (isExtension) {
        return chrome.runtime.getURL('sounds/' + file + '.opus');
    }
    else {
        return 'https://geweldige-geluidseffecten.netlify.app/' + file + '.opus';
    }
}
// VERSION & SAVE MANAGEMENT
// This script is used to save data for both the Extension and the Userscript version. Also contains indexedDB and localStorage as fallback storage.

let versionJson = JSON.parse(window.getResourceAsText('version_info.json'));

const version = versionJson.version;
const platform = versionJson.platform;
const minified = versionJson.minified;
const version_name = versionJson.version_name;
const contributors = versionJson.contributors;

let data;
const isExtension = platform != 'Userscript' && platform != 'Android';
const hasSettingsHash = window.location.hash == '#mod-settings';
let storageMethod;
// Check if userscriptmanager allows storage access
if (typeof GM_getValue === 'function' && typeof GM_setValue === 'function') {
    storageMethod = 'userscript';
    function get(key) {
        return GM_getValue(key, null);
    }
    function set(key, value) {
        return GM_setValue(key, value);
    }
    if (platform != 'Userscript') {
        setTimeout(console.warn.bind(console, 'SOMTODAY MOD: Userscript storage is used while the platform is not set to Userscript.'));
    }
}
// Check if extension allows storage access
else if (((typeof chrome !== 'undefined') && chrome.storage) && chrome.storage.local) {
    storageMethod = 'extension';
    chrome.storage.local.get(null).then((result) => {
        data = result;
    });
    chrome.storage.onChanged.addListener((changes) => {
        if (changes['enabled'] != null) {
            window.location.reload();
        }
    });

    function get(key) {
        if (data == null) {
            return '';
        }
        if (data[key] == null) {
            return '';
        }
        return data[key];
    }
    function set(key, value) {
        let prop = key;
        let obj = {};
        obj[prop] = value;
        try {
            chrome.storage.local.set(obj);
        }
        catch (e) {
            setTimeout(console.warn.bind(console, 'SOMTODAY MOD: Couldn\'t save value. Somtoday Mod is probably updating right now.\nError: ' + e));
        }
        data[key] = value;
    }
    if (!isExtension) {
        setTimeout(console.warn.bind(console, 'SOMTODAY MOD: Extension storage is used while the platform is set to ' + platform + '.'));
    }
}
// Check if indexedDB is supported
else if (window?.indexedDB) {
    storageMethod = 'indexedDB';
    const DB_NAME = 'app-storage';
    const STORE_NAME = 'kv';
    const DB_VERSION = 1;

    async function persistStorage() {
        if (!navigator.storage || !navigator.storage.persist) {
            return false;
        }

        const alreadyPersisted = await navigator.storage.persisted();
        if (alreadyPersisted) {
            return true;
        }

        try {
            return await navigator.storage.persist();
        } catch (e) {
            return false;
        }
    }

    async function openDB() {
        const persistent = await persistStorage();
        if (!persistent) {
            setTimeout(console.warn.bind(console, 'SOMTODAY MOD: Storage is not persistent.'));
        }

        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME, DB_VERSION);

            request.onupgradeneeded = () => {
                const db = request.result;
                if (!db.objectStoreNames.contains(STORE_NAME)) {
                    db.createObjectStore(STORE_NAME);
                }
            };

            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
    }

    async function getAllFromStore() {
        data = await realGetAllFromStore();
    }

    async function realGetAllFromStore() {
        const db = await openDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(STORE_NAME, "readonly");
            const store = tx.objectStore(STORE_NAME);

            const valuesReq = store.getAll();
            const keysReq = store.getAllKeys();

            tx.oncomplete = () => {
                const map = {};
                keysReq.result.forEach((key, i) => {
                    map[key] = valuesReq.result[i];
                });
                resolve(map);
            };

            tx.onerror = () => reject(tx.error);
        });
    }

    function set(key, value) {
        data[key] = value;
        realSet(key, value);
    }

    async function realSet(key, value) {
        const db = await openDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).put(value, key);
            tx.oncomplete = () => resolve(true);
            tx.onerror = () => reject(tx.error);
        });
    }

    function get(key) {
        if (data == null) {
            return '';
        }
        if (data[key] == null) {
            return '';
        }
        return data[key];
    }

    getAllFromStore();
}
// Fallback to local storage
else if (window?.localStorage) {
    storageMethod = 'localStorage';
    let messageShown = false;
    function set(key, value) {
        try {
            localStorage.setItem(key, value);
        }
        catch (e) {
            if (messageShown == false) {
                if (confirm('De LocalStorage-limiet is bereikt. Sommige instellingen zijn niet opgeslagen.\nControleer of je Somtoday Mod ' + (platform == 'Userscript' ? 'GM_getValue en GM_setValue hebt gegrant' : 'toestemming hebt gegeven tot de storage') + ' als je meer opslagruimte wil.\nWil je de LocalStorage wissen?')) {
                    localStorage.clear();
                    window.location.reload();
                }
                messageShown = true;
            }
        }
    }
    function get(key) {
        return localStorage.getItem(key);
    }
    setTimeout(console.warn.bind(console, 'SOMTODAY MOD: Could not find extension or userscript storage. Falling back to localstorage.'));
}
else {
    throw new Error('Somtoday Mod ERROR\nCould not find any place to store setting data.\nConsider updating your browser, or giving Somtoday Mod storage access.');
}
// Remember to open settings if settings hash is present
if (hasSettingsHash) {
    set('opensettingsIntention', '1');
}
// COLORS

// Adjust color with specified amount (make color brighter or darker)
const adjust = (col, amt) => {
    col = col.replace(/^#/, '');
    if (col.length === 3) {
        col = col[0] + col[0] + col[1] + col[1] + col[2] + col[2];
    }
    let [r, g, b] = col.match(/.{2}/g);
    [r, g, b] = [parseInt(r, 16) + amt, parseInt(g, 16) + amt, parseInt(b, 16) + amt];
    r = Math.max(Math.min(255, r), 0).toString(16);
    g = Math.max(Math.min(255, g), 0).toString(16);
    b = Math.max(Math.min(255, b), 0).toString(16);
    const rr = (r.length < 2 ? '0' : '') + r;
    const gg = (g.length < 2 ? '0' : '') + g;
    const bb = (b.length < 2 ? '0' : '') + b;
    return `#${rr}${gg}${bb}`;
};

// Convert hex to rgb
const hexToRgb = hex => hex.replace(/^#?([a-f\d])([a-f\d])([a-f\d])$/i, (m, r, g, b) => '#' + r + r + g + g + b + b).substring(1).match(/.{2}/g).map(x => parseInt(x, 16));

// Convert rgb to hex
const rgbToHex = (r, g, b) => '#' + [r, g, b].map(x => {
    const hex = x.toString(16);
    return hex.length === 1 ? '0' + hex : hex;
}).join('');

// Get brightness of color
const getRelativeLuminance = (rgb) => Math.round(0.2126 * rgb[0] + 0.7152 * rgb[1] + 0.0722 * rgb[2]);

// Change specific color channel
function adjustColorChannel(channel, hex, value) {
    let rgb = hexToRgb(hex);
    rgb[channel] = Math.min(Math.max(rgb[channel] + value, 0), 255);
    return rgbToHex(rgb[0], rgb[1], rgb[2]);
}

// Change color brightness level
function toBrightnessValue(color, target) {
    let i;
    let brightness;
    const startColor = color;
    for (i = 1; i <= 5; i++) {
        brightness = Math.round(getRelativeLuminance(hexToRgb(color)));
        color = adjust(color, target - brightness);
    }
    // Some colors are very bright on one channel (such as default blue)
    // When the target brightness is too high, these colors will look weird (eg default blue looks too green)
    // This code lowers the 2 other color channels to make sure the color looks good
    const rgbcolor = hexToRgb(startColor);
    const factor = Math.round(target * -0.15);
    if (rgbcolor[2] > rgbcolor[0] && rgbcolor[2] > rgbcolor[1] && rgbcolor[2] + 50 > rgbcolor[0] + rgbcolor[1]) {
        color = adjustColorChannel(1, adjustColorChannel(0, color, factor), factor);
    }
    else if (rgbcolor[0] > rgbcolor[2] && rgbcolor[0] > rgbcolor[1] && rgbcolor[0] + 50 > rgbcolor[1] + rgbcolor[2]) {
        color = adjustColorChannel(2, adjustColorChannel(1, color, factor), factor);
    }
    else if (rgbcolor[1] > rgbcolor[0] && rgbcolor[1] > rgbcolor[2] && rgbcolor[1] + 50 > rgbcolor[0] + rgbcolor[2]) {
        color = adjustColorChannel(2, adjustColorChannel(0, color, factor), factor);
    }
    return color;
}

function addNightTheme() {
    if (id('mod-night-theme')) {
        return;
    }

    if (cn('toggle-systeemvoorkeur', 0)) {
        // Update system preferences state (might be unset or outdated otherwise)
        set('autotheme', cn('toggle-systeemvoorkeur', 0).ariaChecked == 'true' ? 'true' : 'false');

        cn('toggle-systeemvoorkeur', 0).addEventListener('click', function () {
            // We need to disable the night theme if follow system preference is enabled
            if (this.ariaChecked == 'true') {
                set('autotheme', 'true');
                // Enable dark, since this is the current preference
                if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
                    if (cn('container dark', 0) && cn('container dark', 0).ariaChecked == 'false') {
                        cn('container dark', 0).click();
                        this.click();
                    }
                }
                // Enable light, since this is the current preference
                else {
                    if (cn('container light', 0) && cn('container light', 0).ariaChecked == 'false') {
                        cn('container light', 0).click();
                        this.click();
                    }
                }
            }
            // Follow system preferences is disabled
            else {
                set('autotheme', 'false');
            }

            // Update checkbox state to make it match the now visually active theme
            updateTheme();
        });
    }

    // Insert night mode option
    const blokDiv = document.querySelector('div.blok');
    const darkDiv = blokDiv.querySelector('div[data-gtm="instellingen-weergave-theme-dark-mode"]');
    const darkImage = darkDiv.getElementsByTagName('img')[0];
    const nightDiv = darkDiv.cloneNode(true);
    nightDiv.id = 'mod-night-theme';
    nightDiv.getElementsByTagName('label')[0].title = 'Toegevoegd door Somtoday Mod';
    nightDiv.getElementsByTagName('label')[0].innerHTML = 'Night ' + window.logo(null, null, '#0099ff', 'height:1em;width:fit-content;margin-left:5px;transform:translateY(2px);');
    nightDiv.getElementsByTagName('input')[0].value = 'night';
    nightDiv.getElementsByTagName('input')[0].checked = get('theme') == 'night';
    nightDiv.setAttribute('aria-label', 'Weergave nacht');
    // The dark-mode image uses #111111 as bg color, which is already pretty dark, and does not match the real bg color used
    // This means that instead of giving night-mode a new image, we modify the image used for dark-mode to use #20262D as bg color
    if (darkImage) {
        darkImage.src = window.getResource('images/dark-mode.svg');
    }
    darkDiv.insertAdjacentElement('afterend', nightDiv);

    // Since we've added the night div now, we need to properly set the selected item
    // We do so based on the html classList, which is up-to-date (handled by initTheme() in main_functions.js)
    const allRadios = blokDiv.querySelectorAll('input[type="radio"][name="thema"]');
    const html = document.documentElement;
    const currentTheme = ['light', 'dark', 'night'].find(t => html.classList.contains(t));
    if (currentTheme) {
        const activeRadio = Array.from(allRadios).find(r => r.value === currentTheme);
        if (activeRadio) {
            activeRadio.checked = true;
        }
    }

    // Whenever the user clicks a theme, we need to update the state
    function updateTheme() {
        const html = document.documentElement;
        allRadios.forEach(r => {
            r.parentElement.setAttribute('aria-checked', r.checked ? 'true' : 'false');
        });
        html.classList.remove('light', 'dark', 'night');
        const checkedRadio = Array.from(allRadios).find(r => r.checked);
        if (checkedRadio && (checkedRadio.value == 'light' || checkedRadio.value == 'dark' || checkedRadio.value == 'night')) {
            // Save theme value, and update html classList to also display theme
            html.classList.add(checkedRadio.value);
            set('theme', checkedRadio.value);

            // If night is selected, we're not following system preferences anymore
            if (checkedRadio.value == 'night' && cn('toggle-systeemvoorkeur', 0) && cn('toggle-systeemvoorkeur', 0).ariaChecked == 'true') {
                cn('toggle-systeemvoorkeur', 0).click();
            }
        }
    }
    updateTheme();
    allRadios.forEach(r => {
        const div = r.parentElement;
        div.addEventListener('click', () => {
            r.checked = true;
            updateTheme();
        });
    });
}
const waitForTabs = new MutationObserver((mutations, obs) => {
    const tabs = document.querySelectorAll('sl-account-modal-tab');
    if (tabs.length >= 2) {
        const secondTab = tabs[1];
        const tabObserver = new MutationObserver(() => {
            if (secondTab.getAttribute('aria-selected') === 'true') {
                addNightTheme();
                tabObserver.disconnect();
            }
        });
        tabObserver.observe(secondTab, { attributes: true });
    }
});
waitForTabs.observe(document.body, { childList: true, subtree: true });
// MINIGAMES
// All minigames
function errorPage() {
    if (!n(tn('hmy-button', 0))) {
        tn('hmy-button', 0).insertAdjacentHTML('afterend', '<a id="mod-play-game">Of speel een game</a>');

        const overlay = document.createElement('div');
        overlay.id = 'mod-game-select';
        overlay.innerHTML = `
            <div id="mod-game-select-box">
                <h2>Kies een game</h2>
                <a data-game="the-dungeon" class="mod-setting-button">The dungeon</a>
                <a data-game="the-escape" class="mod-setting-button">The escape</a>
                <a data-game="grade-defender" class="mod-setting-button">Grade defender</a>
                <a id="mod-game-select-close">Annuleren</a>
            </div>
        `;
        overlay.addEventListener('click', function (e) {
            const game = e.target.dataset.game;
            if (game) {
                const url = new URL(window.location);
                url.searchParams.set('mod-play', game);
                history.replaceState(null, '', url);

                document.body.removeChild(overlay);

                execute([
                    game === 'the-dungeon' ? startTheDungeon :
                    game === 'the-escape' ? startTheEscape :
                    game === 'grade-defender' ? startGradeDefender : null
                ]);
            } else if (e.target.id === 'mod-game-select-close') {
                document.body.removeChild(overlay);
            }
        });

        id('mod-play-game').addEventListener('click', function () {
            document.body.appendChild(overlay);
        });

        const hashGame = window.location.hash.replace('#mod-play=', '');
        const params = new URLSearchParams(window.location.search);
        const queryGame = params.get('mod-play');
        const autoGame = hashGame || queryGame;

        if (autoGame) {
            const gameFunc =
                autoGame === 'the-dungeon' ? startTheDungeon :
                autoGame === 'the-escape' ? startTheEscape :
                autoGame === 'grade-defender' ? startGradeDefender : null;

            if (gameFunc) gameFunc();
        }

        if (window.location.hash === '#mod-play' && !autoGame) {
            id('mod-play-game').click();
            history.replaceState('', document.title, window.location.pathname + window.location.search);
        }
    }
}
